// Cart Logic for Virtuosa
let cartOperationLock=!1;let cartItemsContainer,subtotalElement,totalElement;async function getCart(){const t=localStorage.getItem("token");if(t)try{const e=await fetch(`${API_BASE}/cart`,{headers:{Authorization:`Bearer ${t}`}});if(e.ok){const t=await e.json();return console.log("📦 Cart from backend (logged in user):",t),t.items||[]}throw new Error("Backend cart unavailable")}catch(t){console.warn("⚠️ Backend cart unavailable, using localStorage")}try{const t=localStorage.getItem("virtuosa_cart");return t?JSON.parse(t):[]}catch(t){return console.error("Error parsing cart from localStorage:",t),[]}}async function saveCart(t){if(cartOperationLock)return void console.warn("Cart operation in progress, please wait...");cartOperationLock=!0;const e=localStorage.getItem("token");try{if(e){const o=await fetch(`${API_BASE}/cart`,{method:"POST",headers:{"Content-Type":"application/json",Authorization:`Bearer ${e}`},body:JSON.stringify({items:t})});if(o.ok){const e=await o.json();console.log("✅ Cart saved to backend:",e),localStorage.setItem("virtuosa_cart",JSON.stringify(t)),renderCart();return}throw new Error("Backend save failed")}localStorage.setItem("virtuosa_cart",JSON.stringify(t)),renderCart()}catch(t){console.error("❌ Cart save error:",t),e||localStorage.setItem("virtuosa_cart",JSON.stringify(t)),renderCart()}finally{cartOperationLock=!1}}function calculateTotals(t){return t.reduce((t,e)=>t+e.price*e.quantity,0)}async function addToCart(t,e=1){if(e<1)return void console.error("Quantity must be at least 1");const o=await getCart(),n=o.find(e=>e._id===t||e.product&&e.product._id===t);n?(n.quantity+=e,console.log(`📈 Updated quantity for product ${t}: ${n.quantity}`)):(o.push({_id:t,quantity:e,addedAt:new Date().toISOString()}),console.log(`➕ Added product ${t} to cart`)),await saveCart(o)}async function removeFromCart(t){const e=await getCart(),o=e.filter(e=>e._id!==t&&(!e.product||e.product._id!==t));o.length!==e.length?(console.log(`🗑️ Removed product ${t} from cart`),await saveCart(o)):console.warn(`Product ${t} not found in cart`)}async function updateQuantity(t,e){if(e<1)return void removeFromCart(t);const o=await getCart(),n=o.find(o=>o._id===t||o.product&&o.product._id===t);n?(n.quantity=e,console.log(`🔄 Updated quantity for product ${t}: ${e}`),await saveCart(o)):console.warn(`Product ${t} not found in cart`)}async function clearCart(){try{const t=localStorage.getItem("token");if(t){const e=await fetch(`${API_BASE}/cart`,{method:"DELETE",headers:{Authorization:`Bearer ${t}`}});e.ok&&console.log("✅ Cart cleared on backend")}localStorage.removeItem("virtuosa_cart"),console.log("🗑️ Cart cleared locally"),renderCart()}catch(t){console.error("❌ Error clearing cart:",t),localStorage.removeItem("virtuosa_cart"),renderCart()}}function renderCart(){if(!cartItemsContainer)return;const t=cartItemsContainer.querySelector(".empty-cart");t&&t.remove();const e=cartItemsContainer.querySelector(".cart-items");e&&(e.innerHTML=""),getCart().then(o=>{if(0===o.length){const t=document.createElement("div");t.className="empty-cart text-center py-8",t.innerHTML='<p class="text-gray-500">Your cart is empty</p>',cartItemsContainer.appendChild(t)}else{const t=document.createElement("div");t.className="cart-items space-y-4",t.innerHTML=o.map(t=>{const e=t.product||t,o=e.price?e.price.toLocaleString():"0";return`\n                    <div class="cart-item flex items-center justify-between p-4 border rounded-lg">\n                        <div class="flex items-center space-x-4">\n                            <img src="${e.image||"https://placehold.co/50x50"}" alt="${e.name||"Product"}" class="w-12 h-12 object-cover rounded">\n                            <div>\n                                <h4 class="font-medium">${e.name||"Unknown Product"}</h4>\n                                <p class="text-sm text-gray-500">K${o} x ${t.quantity}</p>\n                            </div>\n                        </div>\n                        <div class="flex items-center space-x-2">\n                            <button onclick="updateQuantity('${t._id}', ${t.quantity-1})" class="px-2 py-1 bg-gray-200 rounded hover:bg-gray-300">-</button>\n                            <span class="px-2">${t.quantity}</span>\n                            <button onclick="updateQuantity('${t._id}', ${t.quantity+1})" class="px-2 py-1 bg-gray-200 rounded hover:bg-gray-300">+</button>\n                            <button onclick="removeFromCart('${t._id}')" class="px-2 py-1 bg-red-500 text-white rounded hover:bg-red-600">×</button>\n                        </div>\n                    </div>\n                `}).join(""),cartItemsContainer.appendChild(t)}const n=calculateTotals(o);subtotalElement&&(subtotalElement.textContent=`K${n.toLocaleString()}`),totalElement&&(totalElement.textContent=`K${n.toLocaleString()}`)})}function initCart(){cartItemsContainer=document.getElementById("cart-items"),subtotalElement=document.getElementById("cart-subtotal"),totalElement=document.getElementById("cart-total"),renderCart()}document.addEventListener("DOMContentLoaded",initCart),window.addToCart=addToCart,window.removeFromCart=removeFromCart,window.updateQuantity=updateQuantity,window.clearCart=clearCart;
